noncompliant:
void process_array(int arr[static 10]) {
  // Noncompliant: static keyword used in array parameter
  for (int i = 0; i < 10; i++) {
    arr[i] *= 2;
  }
}

compliant:
void process_array(int arr[], int size) {
  // Compliant: traditional array parameter
  for (int i = 0; i < size; i++) {
    arr[i] *= 2;
  }
}
